#!/usr/bin/env node
/* livery-lens web — test harness (no dependencies; node docs/tests/run-tests.mjs)
 *
 * Covers the pure pipeline math ported from extract.py:
 *   1. sRGB -> CIELAB against published reference values
 *   2. LAB round-trip
 *   3. deltaE76
 *   4. k-means determinism (fixed seed)
 *   5. palette + role parity against a fixture generated by the Python CLI
 *      on the committed synthetic test image
 *   6. clearcoat_starter schema parity
 *   7. headless u2netp smoke test: the vendored model loads under
 *      onnxruntime and produces a mask on the synthetic image
 */

import { readFileSync } from "node:fs";
import { inflateSync } from "node:zlib";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";
import {
  srgbToLab, labToSrgb, deltaE76, hexOfRgb, kmeans, mulberry32,
  extractPalette, assignRoles, medianFilterLabels, zoneGeometry,
  paletteJson, clearcoatStarter,
} from "../js/pipeline.js";
import {
  buildInputTensor, maskFromOutput, heuristicMask, cleanMask, maskArea,
  resizeBilinear, U2NET_SIZE,
} from "../js/segment.js";

const HERE = dirname(fileURLToPath(import.meta.url));

let passed = 0, failed = 0;
function check(name, cond, detail = "") {
  if (cond) { passed++; console.log(`  ok   ${name}`); }
  else { failed++; console.log(`  FAIL ${name} ${detail}`); }
}
function approx(a, b, tol) { return Math.abs(a - b) <= tol; }

// ------------------------------------------------- minimal PNG decoder
// Supports what cv2.imwrite emits: 8-bit RGB/RGBA/gray, non-interlaced.
function decodePng(path) {
  const buf = readFileSync(path);
  if (buf.readUInt32BE(0) !== 0x89504e47) throw new Error("not a PNG");
  let pos = 8, w = 0, h = 0, colorType = 0, bitDepth = 0;
  const idat = [];
  while (pos < buf.length) {
    const len = buf.readUInt32BE(pos);
    const type = buf.toString("ascii", pos + 4, pos + 8);
    const data = buf.subarray(pos + 8, pos + 8 + len);
    if (type === "IHDR") {
      w = data.readUInt32BE(0); h = data.readUInt32BE(4);
      bitDepth = data[8]; colorType = data[9];
      if (bitDepth !== 8 || data[12] !== 0) throw new Error("unsupported PNG");
    } else if (type === "IDAT") idat.push(data);
    else if (type === "IEND") break;
    pos += 12 + len;
  }
  const channels = { 0: 1, 2: 3, 4: 2, 6: 4 }[colorType];
  const raw = inflateSync(Buffer.concat(idat));
  const stride = w * channels;
  const out = new Uint8ClampedArray(w * h * 4);
  const prev = new Uint8Array(stride);
  const cur = new Uint8Array(stride);
  for (let y = 0; y < h; y++) {
    const filter = raw[y * (stride + 1)];
    const row = raw.subarray(y * (stride + 1) + 1, (y + 1) * (stride + 1));
    for (let x = 0; x < stride; x++) {
      const a = x >= channels ? cur[x - channels] : 0;
      const b = prev[x];
      const c = x >= channels ? prev[x - channels] : 0;
      let v = row[x];
      if (filter === 1) v += a;
      else if (filter === 2) v += b;
      else if (filter === 3) v += Math.floor((a + b) / 2);
      else if (filter === 4) {
        const p = a + b - c, pa = Math.abs(p - a), pb = Math.abs(p - b), pc = Math.abs(p - c);
        v += (pa <= pb && pa <= pc) ? a : (pb <= pc ? b : c);
      }
      cur[x] = v & 0xff;
    }
    for (let x = 0; x < w; x++) {
      const o = (y * w + x) * 4, s = x * channels;
      if (channels >= 3) {
        out[o] = cur[s]; out[o + 1] = cur[s + 1]; out[o + 2] = cur[s + 2];
        out[o + 3] = channels === 4 ? cur[s + 3] : 255;
      } else {
        out[o] = out[o + 1] = out[o + 2] = cur[s];
        out[o + 3] = channels === 2 ? cur[s + 1] : 255;
      }
    }
    prev.set(cur);
  }
  return { width: w, height: h, rgba: out };
}

// ------------------------------------------------------------- 1. LAB
console.log("1. sRGB -> CIELAB reference values");
{
  const cases = [
    [[255, 255, 255], [100, 0, 0]],
    [[0, 0, 0], [0, 0, 0]],
    [[255, 0, 0], [53.24, 80.09, 67.20]],
    [[0, 255, 0], [87.735, -86.183, 83.179]],
    [[0, 0, 255], [32.30, 79.19, -107.86]],
    [[119, 119, 119], [50.03, 0, 0]],
  ];
  for (const [[r, g, b], want] of cases) {
    const got = srgbToLab(r, g, b);
    check(`rgb(${r},${g},${b})`,
      approx(got[0], want[0], 0.05) && approx(got[1], want[1], 0.05) && approx(got[2], want[2], 0.05),
      `got [${got.map((v) => v.toFixed(3))}] want [${want}]`);
  }
}

console.log("2. LAB round-trip");
{
  const rng = mulberry32(7);
  let worst = 0;
  for (let i = 0; i < 500; i++) {
    const r = Math.floor(rng() * 256), g = Math.floor(rng() * 256), b = Math.floor(rng() * 256);
    const [r2, g2, b2] = labToSrgb(...srgbToLab(r, g, b));
    worst = Math.max(worst, Math.abs(r - r2), Math.abs(g - g2), Math.abs(b - b2));
  }
  check("500 random colors round-trip within 1/255 per channel", worst <= 1, `worst=${worst}`);
}

console.log("3. deltaE76");
{
  check("identical -> 0", deltaE76([50, 10, -10], [50, 10, -10]) === 0);
  check("L-only", approx(deltaE76([50, 0, 0], [60, 0, 0]), 10, 1e-9));
  check("3-4-12 -> 13", approx(deltaE76([0, 0, 0], [3, 4, 12]), 13, 1e-9));
  const w = srgbToLab(255, 255, 255), k = srgbToLab(0, 0, 0);
  check("white vs black = 100", approx(deltaE76(w, k), 100, 0.01));
}

console.log("4. k-means determinism");
{
  const rng = mulberry32(123);
  const n = 3000;
  const pts = new Float64Array(n * 3);
  for (let i = 0; i < n; i++) {
    const c = i % 4;
    pts[i * 3] = c * 25 + rng() * 4;
    pts[i * 3 + 1] = (c % 2) * 40 - 20 + rng() * 4;
    pts[i * 3 + 2] = (c > 1 ? 30 : -30) + rng() * 4;
  }
  const a = kmeans(pts, n, 4, { seed: 42 });
  const b = kmeans(pts, n, 4, { seed: 42 });
  let same = a.centers.length === b.centers.length;
  for (let i = 0; same && i < a.centers.length; i++) same = a.centers[i] === b.centers[i];
  check("same seed -> bit-identical centers", same);
  check("inertia is finite and positive", a.inertia > 0 && Number.isFinite(a.inertia));
  // centers should land near the 4 generated blobs
  let found = 0;
  for (const cx of [0, 25, 50, 75]) {
    for (let j = 0; j < 4; j++) if (Math.abs(a.centers[j * 3] - (cx + 2)) < 3) { found++; break; }
  }
  check("4 blob centers recovered", found === 4, `found=${found}`);
}

console.log("5. palette parity vs Python CLI fixture (synthetic.png)");
const img = decodePng(join(HERE, "fixtures", "synthetic.png"));
{
  const fixture = JSON.parse(readFileSync(join(HERE, "fixtures", "palette.json"), "utf8"));
  const { clusters, labelMap, liveryCount } =
    extractPalette(img.rgba, img.width, img.height, null, 7);
  assignRoles(clusters);

  check("cluster count matches", clusters.length === fixture.colors.length,
    `js=${clusters.length} py=${fixture.colors.length}`);
  for (let i = 0; i < Math.min(clusters.length, fixture.colors.length); i++) {
    const js = clusters[i], py = fixture.colors[i];
    const jsLab = srgbToLab(
      parseInt(js.hex.slice(1, 3), 16), parseInt(js.hex.slice(3, 5), 16), parseInt(js.hex.slice(5, 7), 16));
    const pyLab = srgbToLab(
      parseInt(py.hex.slice(1, 3), 16), parseInt(py.hex.slice(3, 5), 16), parseInt(py.hex.slice(5, 7), 16));
    const dE = deltaE76(jsLab, pyLab);
    check(`color ${i}: ${js.hex} ~ ${py.hex} (dE=${dE.toFixed(2)})`, dE < 2.5);
    check(`color ${i}: coverage ${js.coverage.toFixed(3)} ~ ${py.coverage}`,
      approx(js.coverage, py.coverage, 0.01));
    check(`color ${i}: role ${js.role} == ${py.role}`, js.role === py.role);
    check(`color ${i}: saturation ${js.saturation} ~ ${py.saturation}`,
      approx(js.saturation, py.saturation, 0.05));
  }
  check("liveryCount == full frame", liveryCount === img.width * img.height);

  // zone geometry sanity on the median-filtered labels
  const clean = medianFilterLabels(labelMap, img.width, img.height);
  const zones = zoneGeometry(clean, img.width, img.height, clusters, img.width * img.height);
  check("zones: one entry per color", zones.length === clusters.length);
  const baseZone = zones[0];
  check("base zone has at least one region", baseZone.regions.length >= 1);

  // palette.json schema parity
  const pj = paletteJson("synthetic.png", "none", clusters);
  const wantKeys = JSON.stringify(Object.keys(fixture.colors[0]).sort());
  check("palette.json color keys match CLI",
    JSON.stringify(Object.keys(pj.colors[0]).sort()) === wantKeys);
}

console.log("6. clearcoat_starter schema parity");
{
  const fixture = JSON.parse(readFileSync(join(HERE, "fixtures", "clearcoat_starter.json"), "utf8"));
  const { clusters } = extractPalette(img.rgba, img.width, img.height, null, 7);
  assignRoles(clusters);
  const cs = clearcoatStarter("synthetic.png", clusters);
  check("schema id", cs.schema === fixture.schema && cs.schema === "livery-lens/palette@1");
  check("top-level keys match CLI",
    JSON.stringify(Object.keys(cs).sort()) === JSON.stringify(Object.keys(fixture).sort()));
  check("source keys match CLI",
    JSON.stringify(Object.keys(cs.source).sort()) === JSON.stringify(Object.keys(fixture.source).sort()));
  check("color entry keys match CLI",
    JSON.stringify(Object.keys(cs.colors[0]).sort()) === JSON.stringify(Object.keys(fixture.colors[0]).sort()));
  const baseLab = srgbToLab(
    parseInt(cs.baseColor.slice(1, 3), 16), parseInt(cs.baseColor.slice(3, 5), 16), parseInt(cs.baseColor.slice(5, 7), 16));
  const fixLab = srgbToLab(
    parseInt(fixture.baseColor.slice(1, 3), 16), parseInt(fixture.baseColor.slice(3, 5), 16), parseInt(fixture.baseColor.slice(5, 7), 16));
  check("baseColor agrees with CLI (dE<2.5)", deltaE76(baseLab, fixLab) < 2.5);
}

console.log("7. heuristic fallback mask (pure JS, no model)");
{
  const m = heuristicMask(img.rgba, img.width, img.height);
  const area = maskArea(m);
  check("fallback mask non-empty and not full frame",
    area > 0.03 * m.length && area < m.length, `area=${area}/${m.length}`);
}

console.log("8. u2netp loads and segments under Node (vendored ONNX + ort)");
try {
  const { createRequire } = await import("node:module");
  const require = createRequire(import.meta.url);
  const ort = require(join(HERE, "..", "vendor", "ort.wasm.min.js"));
  const { pathToFileURL } = await import("node:url");
  ort.env.wasm.wasmPaths = pathToFileURL(join(HERE, "..", "vendor") + "/").href;
  ort.env.wasm.numThreads = 1;
  const model = readFileSync(join(HERE, "..", "vendor", "u2netp.onnx"));
  const session = await ort.InferenceSession.create(model.buffer.slice(
    model.byteOffset, model.byteOffset + model.byteLength));
  check("session created; has input/output", session.inputNames.length >= 1 && session.outputNames.length >= 1);

  // nearest-neighbour resize synthetic to 320x320 RGBA
  const rgba320 = new Uint8ClampedArray(U2NET_SIZE * U2NET_SIZE * 4);
  for (let y = 0; y < U2NET_SIZE; y++) {
    const sy = Math.min(img.height - 1, Math.floor(y * img.height / U2NET_SIZE));
    for (let x = 0; x < U2NET_SIZE; x++) {
      const sx = Math.min(img.width - 1, Math.floor(x * img.width / U2NET_SIZE));
      const s = (sy * img.width + sx) * 4, d = (y * U2NET_SIZE + x) * 4;
      rgba320[d] = img.rgba[s]; rgba320[d + 1] = img.rgba[s + 1];
      rgba320[d + 2] = img.rgba[s + 2]; rgba320[d + 3] = 255;
    }
  }
  const input = new ort.Tensor("float32", buildInputTensor(rgba320), [1, 3, U2NET_SIZE, U2NET_SIZE]);
  const feeds = {}; feeds[session.inputNames[0]] = input;
  const t0 = Date.now();
  const results = await session.run(feeds);
  const pred = results[session.outputNames[0]].data;
  check("output is 320x320", pred.length === U2NET_SIZE * U2NET_SIZE,
    `len=${pred.length}`);
  const mask = maskFromOutput(pred, img.width, img.height);
  const cleaned = cleanMask(mask, img.width, img.height);
  const area = maskArea(cleaned);
  check(`model produced a non-empty mask (${(area / mask.length * 100).toFixed(0)}% of frame, ${Date.now() - t0}ms)`,
    area > 0);
} catch (e) {
  failed++;
  console.log(`  FAIL u2netp under Node: ${e.message}`);
}

console.log(`\n${passed} passed, ${failed} failed`);
process.exit(failed ? 1 : 0);
